import{_ as t,o as a,c as o,aA as i}from"./chunks/framework.BWqX_Bv-.js";const p=JSON.parse('{"title":"Model","description":"","frontmatter":{},"headers":[],"relativePath":"model.md","filePath":"model.md","lastUpdated":null}'),r={name:"model.md"};function n(s,e,d,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="model" tabindex="-1">Model <a class="header-anchor" href="#model" aria-label="Permalink to &quot;Model&quot;">​</a></h1><p>The model estimates four quantities jointly from the Epuyén line list: the incubation period of Andes hantavirus, the timing of each documented onward transmission relative to its source case&#39;s symptom onset, a weekly time-varying reproduction number R(t), and the over-dispersion of offspring counts per case.</p><p>Because exposure and symptom-onset dates in the line list are recorded as windows rather than exact dates, each case is given two latent variables: a true infection time <code>T_inf</code> and a true symptom-onset time <code>T_onset</code>. The model jointly explores these latent times together with the parameters governing the four quantities above.</p><p>Generation and serial intervals are not given separate priors. They are computed from the fitted incubation period and transmission timing distributions in post-processing: the generation interval is the transmission timing plus the source&#39;s incubation period, and the serial interval is the transmission timing plus the secondary&#39;s incubation period.</p><p>See the <a href="https://github.com/sbfnk/hantavirus/blob/main/README.md" target="_blank" rel="noreferrer">README</a> for headline results and <a href="https://github.com/sbfnk/hantavirus/blob/main/LIMITATIONS.md" target="_blank" rel="noreferrer">LIMITATIONS.md</a> for known caveats.</p><h1 id="latent-variables-and-priors" tabindex="-1">Latent variables and priors <a class="header-anchor" href="#latent-variables-and-priors" aria-label="Permalink to &quot;Latent variables and priors&quot;">​</a></h1><p>Each case has two continuous latent variables. <code>T_onset[i]</code> has a uniform prior over the recorded onset window, which is one day wide if only a single onset date was recorded. <code>T_inf[i]</code> has a uniform prior over the exposure window for sourced cases, or over an 80-day pre-onset window for the zoonotic index.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Quantity</th><th style="text-align:right;">Distribution</th><th style="text-align:right;">Priors</th></tr></thead><tbody><tr><td style="text-align:right;">Incubation period (<code>T_onset − T_inf</code>)</td><td style="text-align:right;">LogNormal</td><td style="text-align:right;">log-mean ~ Normal(3.0, 0.5), log-SD ~ half-Normal(0, 0.5)</td></tr><tr><td style="text-align:right;">Transmission timing relative to source onset (<code>T_inf(sec) − T_onset(src)</code>)</td><td style="text-align:right;">Normal</td><td style="text-align:right;">mean ~ Normal(0, 5), SD ~ half-Normal(0, 1)</td></tr><tr><td style="text-align:right;">Offspring count <code>Z</code> per case</td><td style="text-align:right;">Negative-Binomial with mean <code>R(t)</code> and dispersion <code>k</code></td><td style="text-align:right;"><code>k</code> ~ half-Normal(0.3, 0.5)</td></tr><tr><td style="text-align:right;"><code>log R(t)</code> at weekly knots, linearly interpolated between them</td><td style="text-align:right;">Random walk</td><td style="text-align:right;">first knot ~ Normal(log 1.5, 1); innovation SD ~ half-Normal(0, 0.5)</td></tr></tbody></table><p>A per-pair constraint enforces <code>T_inf(secondary) &gt; T_inf(source)</code> so the generation interval is positive.</p><p>Inference uses NUTS, 4 chains, 1000 post-warmup samples each, <code>target_accept = 0.95</code>. Default seed: 20260508.</p>',10)])])}const g=t(r,[["render",n]]);export{p as __pageData,g as default};
